import React, { useState, useEffect } from 'react';
import './Home.css'; // Import CSS file for styling
import { useCache } from './CacheContext'; // Import the useCache hook
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faPlaneDeparture } from '@fortawesome/free-solid-svg-icons';
import { library } from '@fortawesome/fontawesome-svg-core'; // Import fontawesome library

// Add the icon to the library
library.add(faPlaneDeparture);

interface HomeProps {
    accessToken: string;
    flightResults?: any[]; // Make flightResults optional
}

interface FlightDestination {
    type: string;
    origin: string;
    destination: string;
    departureDate: string;
    returnDate: string;
    price: {
        total: string;
    };
    links: {
        flightDates: string;
        flightOffers: string;
    };
    meta: {
        currency: string;
    };
}

const Home: React.FC<HomeProps> = ({ accessToken }) => {
    const { getCachedResult, updateCache } = useCache(); // Access the cache context
    const [destinations, setDestinations] = useState<FlightDestination[]>([]);
    const [loading, setLoading] = useState<boolean>(true);

    useEffect(() => {
        const fetchFlightDestinations = async () => {
            try {
                // Check if the data is already cached
                const cachedData = getCachedResult('flightDestinations');
                if (cachedData) {
                    setDestinations(cachedData);
                    setLoading(false);
                    return;
                }

                const response = await fetch('https://test.api.amadeus.com/v1/shopping/flight-destinations?origin=PAR&maxPrice=200', {
                    headers: {
                        'Authorization': `Bearer ${accessToken}`
                    }
                });
                const data = await response.json();
                console.log('Data:', data);
                // Check if data contains destinations
                if (data && data.data) {
                    setDestinations(data.data);
                    // Update the cache with the new data
                    updateCache('flightDestinations', data.data);
                    setLoading(false);
                } else {
                    throw new Error('Data is empty or malformed');
                }
            } catch (error) {
                console.error('Error fetching flight destinations:', error);
                setLoading(false);
            }
        };
        fetchFlightDestinations();
    }, [accessToken, getCachedResult, updateCache]);

    return (
        <div className="container">
            <header className="header">
                <h1 className="title">Flight Destinations</h1>
            </header>
            <main>
                {loading ? (
                    <p>Loading flight destinations...</p>
                ) : destinations && destinations.length > 0 ? (
                    <div>
                        <h2 className="subtitle">From Paris (PAR)</h2>
                        <ul className="destination-list">
                            {destinations.map((destination: FlightDestination, index: number) => (
                                <li key={index} className="destination-item">
                                    <p className="destination-name">Destination: {destination.destination}</p>
                                    <p className="price">Price: {destination.price.total} <span className="currency">€</span></p>
                                    <FontAwesomeIcon icon={faPlaneDeparture} />
                                </li>
                            ))}
                        </ul>
                    </div>
                ) : (
                    <p>No flight destinations found</p>
                )}
            </main>
            <footer className="footer">
                <p>&copy; 2024 My Travel Agency</p>
            </footer>
        </div>
    );
};

export default Home;

import React from 'react';
import Home from './Home';

const SearchSpecificFlight: React.FC = () => {
    return <Home />;
};

export default SearchSpecificFlight;

{
  "compilerOptions": {
    "target": "es2016",
